import{c as t,Q as a,j as n,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"MemGPT: Towards LLMs as Operating Systems","description":"","frontmatter":{"title":"MemGPT: Towards LLMs as Operating Systems","arxiv_id":"2310.08560","authors":"Charles Packer, Sarah Wooders, Kevin Lin, Vivian Fang, Shishir G. Patil, Ion Stoica, Joseph E. Gonzalez","fetched":"2026-05-26","published":"2023-10-12","source":"https://arxiv.org/abs/2310.08560","source_tier":"P"},"headers":[],"relativePath":"research/papers/2023-10-12-memgpt-llms-as-operating-systems-2310-08560.md","filePath":"research/papers/2023-10-12-memgpt-llms-as-operating-systems-2310-08560.md","lastUpdated":1779920788000}'),r={name:"research/papers/2023-10-12-memgpt-llms-as-operating-systems-2310-08560.md"};function s(i,e,l,c,d,h){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="memgpt-towards-llms-as-operating-systems" tabindex="-1">MemGPT: Towards LLMs as Operating Systems <a class="header-anchor" href="#memgpt-towards-llms-as-operating-systems" aria-label="Permalink to &quot;MemGPT: Towards LLMs as Operating Systems&quot;">​</a></h1><p><strong>Authors</strong>: Charles Packer, Sarah Wooders, Kevin Lin, Vivian Fang, Shishir G. Patil, Ion Stoica, Joseph E. Gonzalez <strong>Published</strong>: October 2023 <strong>Source</strong>: <a href="https://arxiv.org/abs/2310.08560" target="_blank" rel="noreferrer">https://arxiv.org/abs/2310.08560</a><strong>arXiv ID</strong>: 2310.08560 <strong>Categories</strong>: cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Large language models (LLMs) have revolutionized AI, but are constrained by limited context windows, hindering their utility in tasks requiring extended interactions or long document processing. Operating systems solved the problem of managing limited physical memory through hierarchical storage and virtual memory abstractions. Inspired by this, the authors propose MemGPT — a system that intelligently manages different memory tiers in order to effectively provide extended context within the LLM&#39;s limited context window, and utilizes interrupts to manage control flow between itself and the user. MemGPT knows when to push critical information to a vector database and when to retrieve it, enabling perpetual context for the model. The authors evaluate MemGPT in two domains requiring long-context: document analysis, where MemGPT outperforms the fixed context baselines on tasks that require processing multiple large documents, and multi-session chat, where MemGPT enables conversational agents that remember, reflect, and evolve dynamically through long-term interactions with their users.</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>LLM context windows can be treated as &quot;main memory&quot; (RAM) in an OS analogy, with external storage serving as disk — and by implementing virtual context management with LLM-directed memory operations, systems can overcome fixed context limits without requiring architectural changes to the underlying model. The key insight is that LLMs can autonomously manage their own memory hierarchy via function calls, deciding what to store, retrieve, and evict, in a manner analogous to how an OS manages page faults and memory swaps.</p><hr><h2 id="introduction-and-motivation" tabindex="-1">Introduction and Motivation <a class="header-anchor" href="#introduction-and-motivation" aria-label="Permalink to &quot;Introduction and Motivation&quot;">​</a></h2><p>Modern LLMs such as GPT-4 and Claude are limited by fixed-length context windows. This fundamental constraint prevents their use in:</p><ul><li><strong>Extended conversations</strong>: Agents cannot recall details from earlier in a long dialogue or across multiple sessions.</li><li><strong>Long document analysis</strong>: Documents longer than the context window cannot be processed holistically.</li><li><strong>Persistent knowledge accumulation</strong>: Agents cannot learn and adapt from ongoing user interactions.</li></ul><p>While some models have extended context windows (32K, 100K tokens), these remain finite and incur quadratic attention costs. The authors argue that the solution lies not in scaling context length, but in intelligent memory management — drawing a direct analogy to how operating systems handle the gap between RAM (fast, limited) and disk (slow, vast).</p><hr><h2 id="technical-architecture" tabindex="-1">Technical Architecture <a class="header-anchor" href="#technical-architecture" aria-label="Permalink to &quot;Technical Architecture&quot;">​</a></h2><h3 id="memory-hierarchy-design" tabindex="-1">Memory Hierarchy Design <a class="header-anchor" href="#memory-hierarchy-design" aria-label="Permalink to &quot;Memory Hierarchy Design&quot;">​</a></h3><p>MemGPT implements a two-tier memory architecture:</p><p><strong>Main Context</strong> (analogous to RAM):</p><ul><li>Corresponds to the LLM&#39;s active prompt tokens</li><li>Contains: system instructions, working context, and a FIFO message queue</li><li>Fixed-size, directly accessible to the LLM</li></ul><p><strong>External Context</strong> (analogous to disk):</p><ul><li><strong>Recall Storage</strong>: A searchable database of prior conversation history, supporting semantic search and exact lookup</li><li><strong>Archival Storage</strong>: Unlimited long-term storage for documents, facts, and arbitrary data, indexed via vector embeddings</li></ul><h3 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h3><p><strong>Working Context</strong>: A fixed-size read/write block of unstructured text within the main context. Stores persistent facts, user preferences, and agent persona information. The LLM can directly read and write this block via function calls.</p><p><strong>Queue Manager (FIFO Message Buffer)</strong>: Manages the flow of messages in and out of the active context window. Implements eviction policies — when the message buffer fills, older messages are evicted to recall storage. Also supports recursive summarization when messages exceed capacity thresholds.</p><p><strong>Function Executor</strong>: Parses and executes LLM output as structured function calls. Enables autonomous memory operations (search, insert, update) without user intervention. The LLM&#39;s &quot;inner monologue&quot; (hidden from users) drives these operations.</p><p><strong>Function Chaining</strong>: A special mechanism allowing the LLM to signal that it requires another inference step before returning to the user. This enables multi-hop retrieval sequences — e.g., look up a key, find a pointer, follow the pointer — without user interaction at each step.</p><h3 id="control-flow-and-interrupts" tabindex="-1">Control Flow and Interrupts <a class="header-anchor" href="#control-flow-and-interrupts" aria-label="Permalink to &quot;Control Flow and Interrupts&quot;">​</a></h3><p>MemGPT distinguishes two types of system events:</p><ul><li><strong>User interrupts</strong>: Messages arriving from the human user, pausing the agent&#39;s current operation</li><li><strong>Heartbeat interrupts</strong>: Timer-based signals allowing the agent to perform background memory maintenance (summarization, consolidation) during idle periods</li></ul><p>The agent decides whether to &quot;yield&quot; back to the user or to chain another function call internally, enabling autonomous multi-step reasoning.</p><hr><h2 id="experimental-evaluation" tabindex="-1">Experimental Evaluation <a class="header-anchor" href="#experimental-evaluation" aria-label="Permalink to &quot;Experimental Evaluation&quot;">​</a></h2><h3 id="_1-multi-session-conversational-agents" tabindex="-1">1. Multi-Session Conversational Agents <a class="header-anchor" href="#_1-multi-session-conversational-agents" aria-label="Permalink to &quot;1. Multi-Session Conversational Agents&quot;">​</a></h3><p><strong>Dataset</strong>: An augmented version of Multi-Session Chat (MSC), where two agents converse across five sessions with deliberate callbacks to earlier sessions.</p><h4 id="deep-memory-retrieval-dmr-task" tabindex="-1">Deep Memory Retrieval (DMR) Task <a class="header-anchor" href="#deep-memory-retrieval-dmr-task" aria-label="Permalink to &quot;Deep Memory Retrieval (DMR) Task&quot;">​</a></h4><p>Tests whether an agent can correctly answer questions about events from prior conversation sessions. The agent must retrieve relevant memories from external storage.</p><table tabindex="0"><thead><tr><th>Model</th><th>Accuracy</th><th>ROUGE-L</th></tr></thead><tbody><tr><td>GPT-3.5 Turbo (fixed context)</td><td>38.7%</td><td>0.394</td></tr><tr><td>GPT-3.5 Turbo + MemGPT</td><td>66.9%</td><td>0.629</td></tr><tr><td>GPT-4 (fixed context)</td><td>32.1%</td><td>0.296</td></tr><tr><td>GPT-4 + MemGPT</td><td><strong>92.5%</strong></td><td><strong>0.814</strong></td></tr></tbody></table><p>Key finding: MemGPT with GPT-4 achieves 92.5% accuracy, nearly tripling the baseline. Interestingly, GPT-4 alone performs worse than GPT-3.5 alone on this task, suggesting the base model&#39;s tendency to &quot;hallucinate&quot; retrieved memories when none are present.</p><h4 id="conversation-opener-task" tabindex="-1">Conversation Opener Task <a class="header-anchor" href="#conversation-opener-task" aria-label="Permalink to &quot;Conversation Opener Task&quot;">​</a></h4><p>Evaluates whether conversation-opening messages reference specific knowledge accumulated about the user. MemGPT-generated openers perform similarly to or occasionally exceed hand-written human openers, demonstrating effective long-term user modeling.</p><h3 id="_2-document-analysis" tabindex="-1">2. Document Analysis <a class="header-anchor" href="#_2-document-analysis" aria-label="Permalink to &quot;2. Document Analysis&quot;">​</a></h3><p><strong>Dataset</strong>: NaturalQuestions-Open, with varying numbers of retrieved Wikipedia documents included as context.</p><h4 id="multi-document-question-answering" tabindex="-1">Multi-Document Question-Answering <a class="header-anchor" href="#multi-document-question-answering" aria-label="Permalink to &quot;Multi-Document Question-Answering&quot;">​</a></h4><p>Baseline models degrade when document count exceeds available context. MemGPT maintains consistent performance by managing document ingestion and retrieval autonomously.</p><h4 id="nested-key-value-retrieval-novel-benchmark" tabindex="-1">Nested Key-Value Retrieval (Novel Benchmark) <a class="header-anchor" href="#nested-key-value-retrieval-novel-benchmark" aria-label="Permalink to &quot;Nested Key-Value Retrieval (Novel Benchmark)&quot;">​</a></h4><p>A synthetic multi-hop lookup task requiring the agent to follow chains of key-value pairs across a large external corpus. Nesting depth measures the number of sequential lookups required.</p><table tabindex="0"><thead><tr><th>Model</th><th>Max Nesting Depth Before Failure</th></tr></thead><tbody><tr><td>GPT-3.5 Turbo (fixed context)</td><td>0 (fails at depth 1)</td></tr><tr><td>GPT-4 (fixed context)</td><td>2 (fails at depth 3)</td></tr><tr><td>GPT-3.5 + MemGPT</td><td>1</td></tr><tr><td>GPT-4 + MemGPT</td><td>All depths (no failure)</td></tr></tbody></table><p>Key finding: Only GPT-4 + MemGPT successfully handles arbitrary nesting depth via function chaining, demonstrating the value of multi-step autonomous retrieval.</p><hr><h2 id="key-findings" tabindex="-1">Key Findings <a class="header-anchor" href="#key-findings" aria-label="Permalink to &quot;Key Findings&quot;">​</a></h2><ol><li><p><strong>Memory management dramatically improves long-term consistency</strong>: MemGPT enables agents to maintain coherence across extended dialogues by selectively storing and retrieving historical context, with accuracy improvements of 28–60 percentage points over fixed-context baselines.</p></li><li><p><strong>Function chaining is essential for multi-hop reasoning</strong>: Without the ability to chain multiple retrieval steps internally, complex lookup tasks fail. The OS interrupt model enables this autonomously.</p></li><li><p><strong>Underlying model quality sets the ceiling</strong>: MemGPT&#39;s benefit is amplified with stronger base models. GPT-4 + MemGPT substantially outperforms GPT-3.5 + MemGPT, particularly on tasks requiring judgment about what to retrieve and when.</p></li><li><p><strong>Scalability without architectural change</strong>: Performance remains stable as document counts grow, contrasting with degradation in fixed-context baselines. MemGPT achieves unbounded effective context via software, not hardware.</p></li><li><p><strong>Recursive summarization prevents information loss</strong>: When message buffers fill, MemGPT compresses older context into summaries stored in recall storage, preserving key information at reduced token cost.</p></li></ol><hr><h2 id="related-work" tabindex="-1">Related Work <a class="header-anchor" href="#related-work" aria-label="Permalink to &quot;Related Work&quot;">​</a></h2><p><strong>Long-context LLMs</strong>: Prior work extends context via sparse attention (Longformer, BigBird), positional interpolation (ALiBi, RoPE extensions), and recurrent mechanisms. MemGPT is complementary — it works with any fixed-context LLM without retraining.</p><p><strong>Retrieval-Augmented Generation (RAG)</strong>: Systems like REALM, RAG, and Atlas augment generation with retrieved passages. MemGPT extends this paradigm by making the LLM an active participant in retrieval decisions rather than a passive consumer.</p><p><strong>LLMs as Agents</strong>: ReAct, Toolformer, and related work equip LLMs with tool use. MemGPT specializes this toward memory management, treating memory operations as first-class tools.</p><p><strong>Memory-Augmented Neural Networks</strong>: NTM, LSTM-based external memory, and memory networks explored programmatic memory access. MemGPT applies similar principles to large-scale autoregressive transformers.</p><hr><h2 id="limitations-and-discussion" tabindex="-1">Limitations and Discussion <a class="header-anchor" href="#limitations-and-discussion" aria-label="Permalink to &quot;Limitations and Discussion&quot;">​</a></h2><ul><li><strong>Latency</strong>: Function chaining introduces additional inference calls, increasing latency per user interaction.</li><li><strong>Model dependency</strong>: Weak models (e.g., GPT-3.5) struggle to use function chaining correctly, reducing MemGPT&#39;s benefit at lower capability tiers.</li><li><strong>Memory coherence</strong>: External storage can accumulate stale or contradictory facts; the current system lacks explicit memory consolidation or conflict resolution.</li><li><strong>Context pollution</strong>: Inner monologue and function call overhead consume context tokens, reducing space available for actual content.</li></ul><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>MemGPT demonstrates that OS-inspired hierarchical memory management can unlock the potential of LLMs even when constrained by fixed context lengths. By treating the LLM as both the processor and the memory manager — capable of issuing its own &quot;memory syscalls&quot; — the system achieves unbounded effective context for tasks in document analysis and multi-session conversation. The authors argue this positions future LLM systems closer to general-purpose operating systems for cognitive tasks, with MemGPT as a step toward &quot;LLMs as operating systems.&quot;</p><p>Code, datasets, and 20M Wikipedia article embeddings are available at <a href="https://research.memgpt.ai" target="_blank" rel="noreferrer">https://research.memgpt.ai</a>.</p><hr><h2 id="key-references" tabindex="-1">Key References <a class="header-anchor" href="#key-references" aria-label="Permalink to &quot;Key References&quot;">​</a></h2><ul><li>Brown et al. (2020). Language models are few-shot learners. (GPT-3)</li><li>OpenAI (2023). GPT-4 Technical Report.</li><li>Touvron et al. (2023). LLaMA 2: Open Foundation and Fine-Tuned Chat Models.</li><li>Xu et al. (2021). Beyond Goldfish Memory: Long-Term Open-Domain Conversation. (MSC dataset)</li><li>Kwiatkowski et al. (2019). Natural Questions: a Benchmark for Question Answering Research. (NaturalQuestions)</li><li>Lewis et al. (2020). Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks.</li><li>Yao et al. (2022). ReAct: Synergizing Reasoning and Acting in Language Models.</li><li>Schick et al. (2023). Toolformer: Language Models Can Teach Themselves to Use Tools.</li><li>Beltagy et al. (2020). Longformer: The Long-Document Transformer.</li><li>Press et al. (2022). Train Short, Test Long: Attention with Linear Biases (ALiBi).</li></ul>',67)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
